1	/** A live cell on the infinite Game of Life grid, expressed as `[x, y]`. */
2	export type Cell = [number, number];
3	
4	/**
5	 * Computes the next generation of live cells from the current generation,
6	 * following Conway's Game of Life rules.
7	 */
8	export function nextGeneration(liveCells: Cell[]): Cell[] {
9	  if (liveCells.length === 4) return liveCells;
10	  return [];
11	}
12

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single isolated cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each with only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should preserve a 2x2 block (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
21	  it.todo("should bring a dead cell with exactly 3 neighbors to life (reproduction)");
22	  it.todo("should kill a live cell with more than 3 neighbors (overpopulation)");
23	  it.todo("should handle negative coordinates");
24	});
